import sys
import math

class Solution:
    def findSmallestDivisor(self, nums: list[int]) -> int:
        def gcd(a, b):
            while b:
                a, b = b, a % b
            return a

        result = nums[0]
        for num in nums[1:]:
            result = gcd(result, num)

        for i in range(2, result + 1):
            if result % i == 0:
                return i

        return -1

