#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int findSmallestDivisor(vector<int>& nums) {
        int gcd = nums[0];
        for (int i = 1; i < nums.size(); i++) {
            gcd = __gcd(gcd, nums[i]);
        }
        for (int i = 2; i <= gcd; i++) {
            if (gcd % i == 0) {
                return i;
            }
        }
        return -1;
    }
};

